"use client";

import { useEffect, useRef, useCallback } from "react";

interface Node {
  layer: number;
  index: number;
  x: number;
  y: number;
  baseRadius: number;
  phase: number;
  pulse: number;
  glowIntensity: number;
}

interface Edge {
  from: Node;
  to: Node;
  cpx: number;
  cpy: number;
  isSkip: boolean;
}

interface Particle {
  edgeIndex: number;
  t: number; // 0 to 1 position along edge
  speed: number;
}

const TAU = Math.PI * 2;
const LAYERS = [5, 7, 9, 7, 5];

// Fixed network dimensions — won't scale with viewport
const BASE_WIDTH = 1400;
const BASE_HEIGHT = 900;

const COL = {
  nodeFill: "hsla(205, 55%, 72%, 0.72)",
  nodeStroke: "hsla(205, 45%, 82%, 0.45)",
  nodeGlow: "hsla(200, 60%, 68%, 0.20)",
  nodeCascade: "hsla(195, 70%, 68%, 0.80)",
  nodeCascadeGlow: "hsla(195, 70%, 65%, 0.25)",
  edge: "hsla(210, 40%, 62%, 0.30)",
  edgeSkip: "hsla(210, 35%, 55%, 0.18)",
  edgeCascade: "hsla(195, 50%, 65%, 0.40)",
  particle: "hsla(200, 80%, 75%, 0.9)",
  particleGlow: "hsla(200, 70%, 65%, 0.3)",
};

const PARTICLE_COUNT = 80;
const PARTICLE_MIN_SPEED = 0.08;
const PARTICLE_MAX_SPEED = 0.2;

function lerp(a: number, b: number, t: number) {
  return a + (b - a) * t;
}

export default function NeuralNetworkField() {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const stateRef = useRef<{
    nodes: Node[];
    edges: Edge[];
    particles: Particle[];
    offsetX: number;
    offsetY: number;
  } | null>(null);

  const initState = useCallback((viewportWidth: number, viewportHeight: number) => {
    const padX = 140;
    const padY = 100;
    const availW = BASE_WIDTH - padX * 2;
    const availH = BASE_HEIGHT - padY * 2;
    const maxNodes = Math.max(...LAYERS);
    const nodeSpacingY = availH / (maxNodes + 1);

    const nodes: Node[] = [];
    for (let l = 0; l < LAYERS.length; l++) {
      const count = LAYERS[l];
      const layerX = padX + (availW * l) / (LAYERS.length - 1);
      const startY = padY + (availH - (count - 1) * nodeSpacingY) / 2;
      for (let i = 0; i < count; i++) {
        nodes.push({
          layer: l,
          index: i,
          x: layerX,
          y: startY + i * nodeSpacingY,
          baseRadius: 2.0 + Math.random() * 0.5,
          phase: Math.random() * TAU,
          pulse: 0,
          glowIntensity: 0,
        });
      }
    }

    const edges: Edge[] = [];
    const nodeByLayer = (l: number) => nodes.filter((n) => n.layer === l);

    for (let l = 0; l < LAYERS.length - 1; l++) {
      const fromNodes = nodeByLayer(l);
      const toNodes = nodeByLayer(l + 1);
      for (const from of fromNodes) {
        for (const to of toNodes) {
          const midX = (from.x + to.x) / 2;
          const midY = (from.y + to.y) / 2;
          const dy = to.y - from.y;
          const bow = Math.min(60, Math.abs(dy) * 0.3 + 15) * (dy > 0 ? 1 : -1);
          edges.push({
            from,
            to,
            cpx: midX,
            cpy: midY + bow * (0.6 + Math.random() * 0.5),
            isSkip: false,
          });
