        [0, 2],
        [1, 3],
        [2, 4],
      ];
      for (const [la, lb] of skipPairs) {
        const fromNodes = nodeByLayer(la);
        const toNodes = nodeByLayer(lb);
        for (let i = 0; i < Math.min(fromNodes.length, toNodes.length); i++) {
